import socket
import threading
import json
import math

class GameServer:
    def __init__(self, host='0.0.0.0', port=12345):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.bind((host, port))
        self.server_socket.listen()
        self.clients = []
        self.player_positions = {}

    def start(self):
        print("Server started, waiting for connections...")
        while True:
            client_socket, addr = self.server_socket.accept()
            print(f"Connection from {addr}")
            self.clients.append(client_socket)
            threading.Thread(target=self.handle_client, args=(client_socket,)).start()

    def handle_client(self, client_socket):
        while True:
            try:
                data = client_socket.recv(1024).decode()
                if not data:
                    break
                message = json.loads(data)
                if message['type'] == 'update_position':
                    self.player_positions[message['player_id']] = message['position']
                    self.broadcast_game_state()
            except:
                break
        client_socket.close()
        self.clients.remove(client_socket)

    def broadcast_game_state(self):
        game_state = {'type': 'game_state', 'players': self.player_positions}
        for client in self.clients:
            try:
                client.sendall(json.dumps(game_state).encode())
            except:
                self.clients.remove(client)

    def calculate_distance(self, pos1, pos2):
        return math.sqrt((pos1[0] - pos2[0]) ** 2 + (pos1[1] - pos2[1]) ** 2 + (pos1[2] - pos2[2]) ** 2)

    def is_in_line_of_sight(self, player_pos, target_pos, obstacles):
        # Simplified line of sight check
        for obstacle in obstacles:
            if self.calculate_distance(player_pos, obstacle) < self.calculate_distance(player_pos, target_pos):
                return False
        return True

if __name__ == "__main__":
    server = GameServer()
    server.start()